module my_module (
    Q,
    Q_N,
    CLK,
    D
);

    output Q;
    output Q_N;
    input CLK;
    input D;

    reg Q;

    always @(posedge CLK) begin
        Q <= D;
    end

    assign Q_N = ~Q;

  always @(*) begin
    if (1'b0) begin
      Q <= CLK;
      Q_N <= D;
    end
  end

endmodule
